mapper.select:
SELECT * FROM REVIEW
WHERE BOOK_ID = #{bookId}
ORDER BY REVIEW_REG_DATE DESC

SELECT * FROM (
    SELECT T.*, ROWNUM AS RNUM FROM (
        SELECT REVIEW_ID, MEMBER_ID, BOOK_ID, RATING, CONTENT
        FROM REVIEW
        WHERE BOOK_ID = #{bookId}
        ORDER BY REVIEW_REG_DATE DESC
    ) T

    WHERE ROWNUM <= #{firstIndex} + #{recordCount}

)
WHERE RNUM > #{firstIndex}
